import org.springframework.http.*;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.client.RestTemplate;

@RestController
public class WebhookController {

    private final RestTemplate restTemplate = new RestTemplate();

    @PostMapping("/webhooks")
    public ResponseEntity<?> handleWebhook(@RequestBody String requestBody) {
        // Assuming the URL is provided in the request body as a JSON object with "url" key.
        Object urlObject = Jackson2JsonProcessor.readValue(requestBody, Map.class).get("url");
        String url = (String) urlObject;

        ResponseEntity<String> response = restTemplate.getForEntity(url, String.class);
        return new ResponseEntity<>(response.getBody(), response.getHeaders(), response.getStatusCode());
    }
}